def get_all_u19_players():
    """Get all U19 players"""
    return U19_PLAYERS


def get_u19_players_by_country(country):
    """Get U19 players filtered by country"""
    return [p for p in U19_PLAYERS if country.lower() in p["country"].lower()]


def search_u19_players(query):
    """Search U19 players by name"""
    query = query.lower()
    return [p for p in U19_PLAYERS if query in p["name"].lower()]
